const THEMES_ORDER = ["方向","读书","一起学","软技能","注意力","时间"];
function weekOfYear() {
  const now = new Date();
  const start = new Date(now.getFullYear(), 0, 1);
  const day = Math.floor((now - start) / 864e5);
  return Math.min(50, Math.max(1, Math.floor(day / 7) + 1));
}
module.exports = { TOPICS, THEMES_ORDER, weekOfYear };
